import React, { useState, useEffect, useCallback } from 'react';
import { useTranslation } from '../hooks/useTranslation';

import { useLenis } from '../hooks/useLenis';

const Services = () => {
  const lenis = useLenis();
  const [activeSidebar, setActiveSidebar] = useState(null);

  const handleOpenSidebar = (id) => {
    setActiveSidebar(id);
    if (lenis) {
      lenis.stop();
    }
  };

  const handleCloseSidebar = useCallback(() => {
    setActiveSidebar(null);
    if (lenis) {
      lenis.start();
    }
  }, [lenis]);





  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === 'Escape' && activeSidebar) {
        handleCloseSidebar();
      }
    };
    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [activeSidebar, handleCloseSidebar]);

  const services = [
    {
      icon: "bi-code-slash",
      title_key: "service_1_title",
      description_key: "service_1_text",
      id: "fullstack"
    },
    {
      icon: "bi-palette",
      title_key: "service_3_title",
      description_key: "service_3_text",
      id: "uiux"
    },
    {
      icon: "bi-card-checklist",
      title_key: "service_4_title",
      description_key: "service_4_text",
      id: "software"
    },
    {
      icon: "bi-bar-chart-line",
      title_key: "service_6_title", 
      description_key: "service_6_text",
      id: "powerbi"
    }
  ];

  const sidebarContent = {
    fullstack: {
      title: "Desenvolvimento Full Stack",
      link: "https://matheusabib.github.io/Tela-de-links-Figma/",
      linkText: "Ver Projetos",
      frontend: ["HTML5", "CSS3", "SCSS", "JavaScript", "TypeScript", "React", "Angular"],
      backend: ["Java", "Spring Boot", "Node.js", "Express", "MySQL"],
      tools: ["Git", "GitHub", "VS Code", "Postman"],
      experience: "Atuo como Desenvolvedor de Software na Prefeitura de Mogi das Cruzes, desenvolvendo sistemas com Angular, TypeScript e Spring Boot seguindo Scrum.",
      differentials: ["Código limpo", "Versionamento Git", "Metodologias ágeis", "Testes e qualidade"],
      process: [
        { step: "01", title: "Análise", desc: "Levantamento de requisitos" },
        { step: "02", title: "Desenvolvimento", desc: "Codificação com Git" },
        { step: "03", title: "Entrega", desc: "Testes e deploy" }
      ]
    },
    uiux: {
      title: "UI/UX Design",
      link: "https://matheusabib.github.io/Tela-de-links-Figma/",
      linkText: "Ver Projetos",
      frontend: ["Figma", "Canva", "Adobe XD"],
      backend: ["UX Research", "Testes de Usabilidade"],
      tools: ["Miro", "Hotjar"],
      experience: "Criação de wireframes e protótipos interativos com foco em usabilidade.",
      differentials: ["Design centrado no usuário", "Prototipagem", "Testes A/B"],
      process: [
        { step: "01", title: "Pesquisa", desc: "Análise de público-alvo" },
        { step: "02", title: "Wireframes", desc: "Definição de arquitetura" },
        { step: "03", title: "Design", desc: "Interface e protótipo" }
      ]
    },
    software: {
      title: "Engenharia de Software",
      link: null,
      linkText: null,
      frontend: ["Scrum", "Kanban"],
      backend: ["UML", "Documentação"],
      tools: ["Trello", "Jira", "Git"],
      experience: "Formação em ADS (Fatec) e Engenharia de Software (UMC).",
      differentials: ["Gestão ágil", "Documentação", "Métricas"],
      process: [
        { step: "01", title: "Requisitos", desc: "Levantamento" },
        { step: "02", title: "Planejamento", desc: "Backlog e sprints" },
        { step: "03", title: "Entrega", desc: "Qualidade e deploy" }
      ]
    },
    powerbi: {
      title: "Power BI & Análise de Dados",
      link: "https://matheusabib.github.io/Tela-de-Links-PowerBI/",
      linkText: "Ver Dashboards",
      frontend: ["Power BI", "Power Query", "DAX"],
      backend: ["Oracle", "SQL Server", "Excel"],
      tools: ["SSMS", "Azure"],
      experience: "Dashboards interativos e modelagem de dados relacionais.",
      differentials: ["ETL", "DAX avançado", "Storytelling"],
      process: [
        { step: "01", title: "ETL", desc: "Coleta e preparação" },
        { step: "02", title: "Modelagem", desc: "Relacionamentos" },
        { step: "03", title: "Dashboard", desc: "Visualizações" }
      ]
    }
  };

  const activeContent = activeSidebar ? sidebarContent[activeSidebar] : null;

  return (
    <>
      <section id="services" className="services section">
        <div className="section-glow"></div>
        <div className="section-waves"></div>
        <div className="section-orbs">
          <div className="orb orb-1"></div>
          <div className="orb orb-2"></div>
          <div className="orb orb-3"></div>
        </div>

        <div className="container">
          <div className="section-title" data-aos="fade-up">
            <h3 data-translate={service.title_key}>{t(service.title_key)}</h3>
          </div>
        </div>

        <div className="container" data-aos="fade-up" data-aos-delay="100">
          <div className="services-grid">
            {services.map((service, index) => (
              <div 
                key={index} 
                className="service-item"
                data-aos="fade-up"
                data-aos-delay={150 + (index * 100)}
              >
                <div className="service-icon">
                  <i className={`bi ${service.icon}`}></i>
                </div>
                <div className="service-content">
                  <h3 data-translate={service.title_key}>{t(service.title_key)}</h3>
                  <p data-translate={service.description_key}>{t(service.description_key)}</p>
                  <a 
                    href="#"
                    className="service-link"
                    onClick={(e) => {
                      e.preventDefault();
                      handleOpenSidebar(service.id);
                    }}
                  >
                    <span data-translate="see_button">{t('see_button')}</span>
                    <i className="bi bi-arrow-right"></i>
                  </a>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      <div className={`sidebar-overlay ${activeSidebar ? 'active' : ''}`} onClick={handleCloseSidebar}></div>
      
      <div className={`service-sidebar ${activeSidebar ? 'active' : ''}`}>
        <div className="sidebar-header">
          <div className="sidebar-header-content">
            <h2>{activeContent?.title}</h2>
            {activeContent?.link && (
              <a href={activeContent.link} target="_blank" rel="noopener noreferrer">
                <i className="bi bi-eye me-2"></i>
                {activeContent.linkText}
              </a>
            )}
          </div>
          <button className="sidebar-close" onClick={handleCloseSidebar}>
            <i className="bi bi-x-lg"></i>
          </button>
        </div>
        
        <div className="sidebar-body">
          <div className="sidebar-grid">
            <div className="sidebar-column">
              <div className="sidebar-section">
                <div className="section-header">
                  <div className="section-icon frontend-icon">
                    <i className="bi bi-window"></i>
                  </div>
                  <h3>Front-end</h3>
                </div>
                <div className="tech-stack-list">
                  {activeContent?.frontend.map((tech, idx) => (
                    <span key={idx} className="stack-tag">{tech}</span>
                  ))}
                </div>
              </div>
              
              <div className="sidebar-section">
                <div className="section-header">
                  <div className="section-icon backend-icon">
                    <i className="bi bi-server"></i>
                  </div>
                  <h3>Back-end</h3>
                </div>
                <div className="tech-stack-list">
                  {activeContent?.backend.map((tech, idx) => (
                    <span key={idx} className="stack-tag">{tech}</span>
                  ))}
                </div>
              </div>

              <div className="sidebar-section">
                <div className="section-header">
                  <div className="section-icon tools-icon">
                    <i className="bi bi-tools"></i>
                  </div>
                  <h3>Ferramentas</h3>
                </div>
                <div className="tech-stack-list">
                  {activeContent?.tools.map((tech, idx) => (
                    <span key={idx} className="stack-tag">{tech}</span>
                  ))}
                </div>
              </div>
            </div>
            
            <div className="sidebar-column">
              <div className="sidebar-section">
                <div className="section-header">
                  <div className="section-icon experience-icon">
                    <i className="bi bi-briefcase"></i>
                  </div>
                  <h3>Experiência</h3>
                </div>
                <div className="Descricao-modal">
                  <p>{activeContent?.experience}</p>
                </div>
              </div>

              <div className="sidebar-section">
                <div className="section-header">
                  <div className="section-icon differential-icon">
                    <i className="bi bi-star"></i>
                  </div>
                  <h3>Diferenciais</h3>
                </div>
                <div className="differentials-list">
                  {activeContent?.differentials.map((diff, idx) => (
                    <span key={idx} className="differential-tag">
                      <i className="bi bi-check-circle-fill"></i>
                      {diff}
                    </span>
                  ))}
                </div>
              </div>

              <div className="sidebar-section process-section">
                <div className="section-header">
                  <div className="section-icon process-icon">
                    <i className="bi bi-diagram-3"></i>
                  </div>
                  <h3>Processo</h3>
                </div>
                
                <div className="process-timeline">
                  {activeContent?.process.map((item, idx) => (
                    <div key={idx} className="process-step">
                      <div className="step-indicator">
                        <span className="step-number-passo">{item.step}</span>
                      </div>
                      <div className="step-content-passo">
                        <div className="step-header">
                          <h4>{item.title}</h4>
                        </div>
                        <p>{item.desc}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

export default Services;
